	dec := json.NewDecoder(r.Body)
	dec.DisallowUnknownFields()
	if err := dec.Decode(&tr); err != nil {
		http.Error(w, "invalid json: "+err.Error(), http.StatusBadRequest)
		return
	}
	if dec.More() {
		http.Error(w, "invalid json: trailing data", http.StatusBadRequest)
		return
	}

	if !s.cfg.AllowHighCardinality {
		http.Error(w, "high-cardinality tracking disabled", http.StatusForbidden)
		return
	}

	userID := sanitizeLabelValue(tr.UserID, s.cfg.MaxLabelValueBytes)
	requestID := sanitizeLabelValue(tr.RequestID, s.cfg.MaxLabelValueBytes)
	route := sanitizeLabelValue(tr.Route, s.cfg.MaxLabelValueBytes)
	method := sanitizeLabelValue(tr.Method, s.cfg.MaxLabelValueBytes)
	status := strconv.Itoa(tr.Status)
